fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }

    // V_MAX represents the maximum possible value + 1. Since nums[i] <= 10^5, we use 100001.
    const V_SIZE: usize = 100001; 
    const INF: i64 = 0; // Scores are non-negative, so 0 is the identity for max operation.

    // --- Segment Tree Implementation for Range Maximum Query ---
    // We need two segment trees: one for DP_DOWN values (to calculate DP_UP) 
    // and one for DP_UP values (to calculate DP_DOWN).

    struct MaxSegmentTree {
        tree: Vec<i64>,
        size: usize,
    }

    impl MaxSegmentTree {
        fn new(v_size: usize) -> Self {
            // Tree array size is usually 4*V_SIZE for safety
            let tree_size = 4 * v_size;
            MaxSegmentTree {
                tree: vec![INF; tree_size],
                size: v_size,
            }
        }

        // Point update: Sets the value at index 'idx' to max(current_value, new_val)
        fn update(&mut self, idx: usize, new_val: i64) {
            self._update(1, 1, self.size, idx, new_val);
        }

        fn _update(&mut self, node: usize, start: usize, end: usize, idx: usize, new_val: i64) {
            if start == end {
                // Leaf node: store the maximum score seen for this value
                self.tree[node] = self.tree[node].max(new_val);
                return;
            }
            let mid = start + (end - start) / 2;
            if idx <= mid {
                self._update(2 * node, start, mid, idx, new_val);
            } else {
                self._update(2 * node + 1, mid + 1, end, idx, new_val);
            }
            // Internal node update: max of children
            self.tree[node] = self.tree[2 * node].max(self.tree[2 * node + 1]);
        }

        // Range query: Returns maximum value in range [l, r]
        fn query(&self, l: usize, r: usize) -> i64 {
            if l > r || l > self.size || r < 1 {
                return INF;
            }
            // Clamp query range to valid bounds [1, size]
            let query_l = l.max(1);
            let query_r = r.min(self.size);

            if query_l > query_r {
                return INF;
            }
            self._query(1, 1, self.size, query_l, query_r)
        }

        fn _query(&self, node: usize, start: usize, end: usize, l: usize, r: usize) -> i64 {
            if r < start || end < l {
                return INF; // Range outside query scope
            }
            if l <= start && end <= r {
                return self.tree[node]; // Current segment fully within query range
            }

            let mid = start + (end - start) / 2;
            let p1 = self._query(2 * node, start, mid, l, r);
            let p2 = self._query(2 * node + 1, mid + 1, end, l, r);

            return p1.max(p2);
        }
    }

    // DP_UP[i]: Max score ending at i, where nums[i] > nums[j] (Up move)
    let mut dp_up = vec![0i64; n];
    // DP_DOWN[i]: Max score ending at i, where nums[i] < nums[j] (Down move)
    let mut dp_down = vec![0i64; n];

    // ST_DOWN stores max(DP_DOWN[j]) keyed by nums[j] for j <= i-k. Used to calculate DP_UP[i].
    let mut st_down = MaxSegmentTree::new(V_SIZE);
    // ST_UP stores max(DP_UP[j]) keyed by nums[j] for j <= i-k. Used to calculate DP_DOWN[i].
    let mut st_up = MaxSegmentTree::new(V_SIZE);

    let mut max_score = 0i64;

    for i in 0..n {
        let v_i = nums[i];

        // 1. Check if the index j = i - k is now eligible to be inserted into the DSs
        if i >= k as usize {
            let j = i - k as usize;
            // Insert DP[j] into the segment trees
            st_up.update(v_i as usize, dp_up[j]);
            st_down.update(v_i as usize, dp_down[j]);
        }

        // 2. Calculate DP_UP[i] (Up move: previous was Down)
        // We need max DP_DOWN[j] where nums[j] < v_i. Range [1, v_i - 1].
        let max_prev_down = st_down.query(1, (v_i - 1) as usize);
        // Score = v_i + max(0, max_prev_down). max(0, ...) handles length 1 case.
        dp_up[i] = v_i + max_prev_down.max(INF);

        // 3. Calculate DP_DOWN[i] (Down move: previous was Up)
        // We need max DP_UP[j] where nums[j] > v_i. Range [v_i + 1, V_SIZE - 1].
        let max_prev_up = st_up.query((v_i + 1) as usize, V_SIZE - 1);
        // Score = v_i + max(0, max_prev_up).
        dp_down[i] = v_i + max_prev_up.max(INF);

        // 4. Update overall maximum score
        max_score = max_score.max(dp_up[i]).max(dp_down[i]);
    }

    max_score
}

