struct SegmentTree {
    tree: Vec<i64>,
    size: usize,
}

impl SegmentTree {
    fn new(max_val: usize) -> Self {
        // Size needed: 4 * max_val + buffer
        let size = 1; // Base size for recursion
        let tree_size = 4 * (max_val + 1);
        SegmentTree {
            tree: vec![0; tree_size],
            size: max_val,
        }
    }

    // Update the value at index 'idx' (1-based value) to max(current, new_val)
    fn update(&mut self, node: usize, start: usize, end: usize, idx: usize, new_val: i64) {
        if start == end {
            // Leaf node reached
            self.tree[node] = max(self.tree[node], new_val);
            return;
        }

        let mid = start + (end - start) / 2;
        if idx <= mid {
            // Go left
            self.update(2 * node, start, mid, idx, new_val);
        } else {
            // Go right
            self.update(2 * node + 1, mid + 1, end, idx, new_val);
        }

        // Update internal node
        self.tree[node] = max(self.tree[2 * node], self.tree[2 * node + 1]);
    }

    // Public facing update wrapper
    fn point_update(&mut self, idx: usize, new_val: i64) {
        if idx == 0 || idx > self.size { return; }
        self.update(1, 1, self.size, idx, new_val);
    }

    // Query the maximum value in the range [l, r] (1-based values)
    fn query(&self, node: usize, start: usize, end: usize, l: usize, r: usize) -> i64 {
        // Out of range
        if r < start || end < l || l > r {
            return 0;
        }

        // Fully within range
        if l <= start && end <= r {
            return self.tree[node];
        }

        // Overlap
        let mid = start + (end - start) / 2;
        let p1 = self.query(2 * node, start, mid, l, r);
        let p2 = self.query(2 * node + 1, mid + 1, end, l, r);

        max(p1, p2)
    }

    // Public facing range query wrapper
    fn range_query(&self, l: usize, r: usize) -> i64 {
        if l > self.size || r < 1 || l > r {
            return 0;
        }
        let l_clip = max(1, l);
        let r_clip = min(self.size, r);
        self.query(1, 1, self.size, l_clip, r_clip)
    }
}


fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }

    // Maximum possible value is 10^5 based on constraints.
    let max_val_i32 = 100000;
    let max_val = max_val_i32; 

