    // We seek DP[j][0] when calculating DP[i][1].
    let mut st0 = SegmentTree::new(max_val);

    // ST_1 tracks max scores ending with 'down' transition (preceded by smaller element).
    // We seek DP[j][1] when calculating DP[i][0].
    let mut st1 = SegmentTree::new(max_val);

    // DP_results[i] stores (DP[i][0], DP[i][1])
    // DP[i][0]: Max score ending at i, where nums[i] > previous (Up movement)
    // DP[i][1]: Max score ending at i, where nums[i] < previous (Down movement)
    let mut dp_results: Vec<(i64, i64)> = vec![(0, 0); n];

    let mut max_score: i64 = 0;

    for i in 0..n {
        let v = nums[i] as usize;

        // --- Step A: Make results from j = i - k available ---
        // These results are now valid to use for calculating DP[i]
        if i >= k as usize {
            let j = i - k as usize;
