        let m1 = st1.range_query(1, v.saturating_sub(1));
        let dp_i_0 = nums[i] + max(0, m1);

        // Calculate DP[i][1]: Sequence ends ... > v. Previous must have been state 0 (Up move).
        // We need max DP[j][0] where nums[j] > v. Query ST_0 in range [v+1, max_val].
        let m0 = st0.range_query(v + 1, max_val);
        let dp_i_1 = nums[i] + max(0, m0);

        // --- Step C: Store results and update overall max score ---
        dp_results[i] = (dp_i_0, dp_i_1);
        max_score = max(max_score, dp_i_0);
        max_score = max(max_score, dp_i_1);
    }

    max_score
