impl SegmentTree {
    fn new(max_val: usize) -> Self {
        // Tree size needs to accommodate 1-based indexing up to max_val.
        let size = max_val + 1;
        // A safe size for a segment tree covering N leaves is usually 4*N.
        let tree_size = 4 * size;
        SegmentTree {
            tree: vec![0; tree_size],
            size: size,
        }
    }

    // Point update: sets the value at index 'idx' to max(current_value, new_val)
    fn update(&mut self, idx: usize, new_val: i64) {
        self._update(1, 1, self.size - 1, idx, new_val);
    }

    fn _update(&mut self, node: usize, start: usize, end: usize, idx: usize, new_val: i64) {
        if start == end {
            self.tree[node] = self.tree[node].max(new_val);
            return;
        }
        let mid = start + (end - start) / 2;
        if idx <= mid {
            self._update(2 * node, start, mid, idx, new_val);
        } else {
            self._update(2 * node + 1, mid + 1, end, idx, new_val);
        }
        self.tree[node] = self.tree[2 * node].max(self.tree[2 * node + 1]);
    }

    // Range maximum query: finds max value in range [l, r]
    fn query_max(&self, l: usize, r: usize) -> i64 {
        if l > r || l >= self.size || r == 0 {
            return 0; // Range invalid or outside bounds, return neutral element (0 since scores are positive)
        }
        let r_capped = r.min(self.size - 1);
        self._query_max(1, 1, self.size - 1, l, r_capped)
    }

    fn _query_max(&self, node: usize, start: usize, end: usize, l: usize, r: usize) -> i64 {
        if r < start || end < l {
            return 0; // No overlap
        }
        if l <= start && end <= r {
            return self.tree[node]; // Full overlap
        }

        let mid = start + (end - start) / 2;
        let p1 = self._query_max(2 * node, start, mid, l, r);
        let p2 = self._query_max(2 * node + 1, mid + 1, end, l, r);
        p1.max(p2)
    }
}

